# lib/blog/posts/post.ex
defmodule Blog.Posts.Post do
  use Ecto.Schema
  import Ecto.Changeset

  schema "posts" do
    field :title, :string
    field :content, :string
    field :sanitized_content, :string
    belongs_to :user, Blog.Accounts.User

    timestamps()
  end

  def changeset(post, attrs) do
    post
    |> cast(attrs, [:title, :content])
    |> validate_required([:title, :content])
    |> sanitize_content()
  end

  defp sanitize_content(changeset) do
    case get_change(changeset, :content) do
      nil ->
        changeset

      content ->
        sanitized = Blog.ContentSanitizer.sanitize(content)
        put_change(changeset, :sanitized_content, sanitized)
    end
  end
end

# lib/blog/content_sanitizer.ex
defmodule Blog.ContentSanitizer do
  @moduledoc """
  Sanitizes user-generated HTML content, allowing safe formatting tags
  while stripping all dangerous elements like <script>, event handlers,
  iframes, etc.
  """

  # Define a custom scrubber that allows rich formatting but blocks XSS vectors
  defmodule BlogScrubber do
    require HtmlSanitizeEx.Scrubber.Meta
    alias HtmlSanitizeEx.Scrubber.Meta

    # Allow safe text formatting tags
    Meta.remove_cdata_sections_before_scrub()
    Meta.strip_comments()

    # Allowed tags with specific allowed attributes
    Meta.allow_tag_with_these_attributes("p", ["class"])
    Meta.allow_tag_with_these_attributes("br", [])
    Meta.allow_tag_with_these_attributes("strong", [])
    Meta.allow_tag_with_these_attributes("b", [])
    Meta.allow_tag_with_these_attributes("em", [])
    Meta.allow_tag_with_these_attributes("i", [])
    Meta.allow_tag_with_these_attributes("u", [])
    Meta.allow_tag_with_these_attributes("s", [])
    Meta.allow_tag_with_these_attributes("blockquote", ["class"])
    Meta.allow_tag_with_these_attributes("code", ["class"])
    Meta.allow_tag_with_these_attributes("pre", ["class"])
    Meta.allow_tag_with_these_attributes("ul", [])
    Meta.allow_tag_with_these_attributes("ol", [])
    Meta.allow_tag_with_these_attributes("li", [])
    Meta.allow_tag_with_these_attributes("h1", [])
    Meta.allow_tag_with_these_attributes("h2", [])
    Meta.allow_tag_with_these_attributes("h3", [])
    Meta.allow_tag_with_these_attributes("h4", [])
    Meta.allow_tag_with_these_attributes("h5", [])
    Meta.allow_tag_with_these_attributes("h6", [])
    Meta.allow_tag_with_these_attributes("hr", [])
    Meta.allow_tag_with_these_attributes("span", ["class"])
    Meta.allow_tag_with_these_attributes("div", ["class"])
    Meta.allow_tag_with_these_attributes("table", ["class"])
    Meta.allow_tag_with_these_attributes("thead", [])
    Meta.allow_tag_with_these_attributes("tbody", [])
    Meta.allow_tag_with_these_attributes("tr", [])
    Meta.allow_tag_with_these_attributes("th", [])
    Meta.allow_tag_with_these_attributes("td", [])

    # Allow links but only with safe href protocols
    Meta.allow_tag_with_uri_attributes("a", ["href"], ["http", "https", "mailto"])
    Meta.allow_tag_with_these_attributes("a", ["title", "class", "rel", "target"])

    # Allow images but only with safe src protocols
    Meta.allow_tag_with_uri_attributes("img", ["src"], ["http", "https"])
    Meta.allow_tag_with_these_attributes("img", ["alt", "title", "class", "width", "height"])

    # Strip everything else (script, iframe, object, embed, form, input, style, event handlers, etc.)
    Meta.strip_everything_not_covered()
  end

  @doc """
  Sanitizes HTML content, allowing safe rich formatting tags
  while removing all potentially dangerous elements and attributes.
  """
  def sanitize(html) when is_binary(html) do
    HtmlSanitizeEx.Scrubber.scrub(html, BlogScrubber)
  end

  def sanitize(_), do: ""
end

# lib/blog_web/live/post_live/show.ex
defmodule BlogWeb.PostLive.Show do
  use BlogWeb, :live_view

  alias Blog.Posts

  @impl true
  def mount(%{"id" => id}, _session, socket) do
    post = Posts.get_post!(id)
    {:ok, assign(socket, :post, post)}
  end

  @impl true
  def render(assigns) do
    ~H"""
    <article class="blog-post">
      <header>
        <h1><%= @post.title %></h1>
        <p class="post-meta">
          By <%= @post.user.name %> · <%= Calendar.strftime(@post.inserted_at, "%B %d, %Y") %>
        </p>
      </header>

      <div class="post-content prose">
        <%!--
          SECURITY: We render sanitized_content, NOT raw user content.
          The content was sanitized on write using Blog.ContentSanitizer
          which strips <script>, event handlers, iframes, and other XSS vectors.

          NEVER do this: raw(@post.content)
        --%>
        <%= raw(@post.sanitized_content) %>
      </div>
    </article>
    """
  end
end

# lib/blog_web/live/post_live/index.ex
defmodule BlogWeb.PostLive.Index do
  use BlogWeb, :live_view

  alias Blog.Posts

  @impl true
  def mount(_params, _session, socket) do
    posts = Posts.list_posts()
    {:ok, assign(socket, :posts, posts)}
  end

  @impl true
  def render(assigns) do
    ~H"""
    <div class="blog-index">
      <h1>Blog Posts</h1>

      <div :for={post <- @posts} class="post-preview">
        <h2>
          <.link navigate={~p"/posts/#{post.id}"}>
            <%= post.title %>
          </.link>
        </h2>
        <div class="post-excerpt prose">
          <%= raw(truncate_sanitized(post.sanitized_content, 300)) %>
        </div>
        <p class="post-meta">
          By <%= post.user.name %> · <%= Calendar.strftime(post.inserted_at, "%B %d, %Y") %>
        </p>
      </div>
    </div>
    """
  end

  defp truncate_sanitized(nil, _), do: ""

  defp truncate_sanitized(html, max_length) when is_binary(html) do
    if String.length(html) <= max_length do
      html
    else
      html
      |> String.slice(0, max_length)
      |> String.replace(~r/<[^>]*$/, "")
      |> Kernel.<>("…")
      |> Blog.ContentSanitizer.sanitize()
    end
  end
end

# lib/blog_web/live/post_live/form.ex
defmodule BlogWeb.PostLive.Form do
  use BlogWeb, :live_view

  alias Blog.Posts
  alias Blog.Posts.Post

  @impl true
  def mount(_params, _session, socket) do
    changeset = Posts.change_post(%Post{})

    {:ok,
     socket
     |> assign(:changeset, changeset)
     |> assign(:form, to_form(changeset))}
  end

  @impl true
  def render(assigns) do
    ~H"""
    <div class="post-editor">
      <h1>Create New Post</h1>

      <.form for={@form} phx-change="validate" phx-submit="save">
        <div class="form-group">
          <.input field={@form[:title]} label="Title" type="text" />
        </div>

        <div class="form-group">
          <label>Content (HTML formatting allowed)</label>
          <p class="help-text">
            You can use: &lt;b&gt;, &lt;i&gt;, &lt;u&gt;, &lt;a&gt;, &lt;img&gt;,
            &lt;h1&gt;-&lt;h6&gt;, &lt;ul&gt;, &lt;ol&gt;, &lt;blockquote&gt;,
            &lt;code&gt;, &lt;pre&gt;, &lt;table&gt;, and more.
          </p>
          <.input field={@form[:content]} label="Content" type="textarea" rows="20" />
        </div>

        <div class="form-group">
          <h3>Preview</h3>
          <div class="post-preview prose">
            <%= raw(Blog.ContentSanitizer.sanitize(@form[:content].value || "")) %>
          </div>
        </div>

        <.button type="submit">Publish Post</.button>
      </.form>
    </div>
    """
  end

  @impl true
  def handle_event("validate", %{"post" => post_params}, socket) do
    changeset =
      %Post{}
      |> Posts.change_post(post_params)
      |> Map.put(:action, :validate)

    {:noreply, assign(socket, form: to_form(changeset))}
  end

  @impl true
  def handle_event("save", %{"post" => post_params}, socket) do
    case Posts.create_post(post_params, socket.assigns.current_user) do
      {:ok, post} ->
        {:noreply,
         socket
         |> put_flash(:info, "Post published successfully!")
         |> push_navigate(to: ~p"/posts/#{post.id}")}

      {:error, changeset} ->
        {:noreply, assign(socket, form: to_form(changeset))}
    end
  end
end

# test/blog/content_sanitizer_test.exs
defmodule Blog.ContentSanitizerTest do
  use ExUnit.Case, async: true

  alias Blog.ContentSanitizer

  test "allows safe formatting tags" do
    html = "<p><strong>Bold</strong> and <em>italic</em></p>"
    assert ContentSanitizer.sanitize(html) == html
  end

  test "allows links with safe protocols" do
    html = ~s(<a href="https://example.com">Link</a>)
    assert ContentSanitizer.sanitize(html) =~ "https://example.com"
  end

  test "strips script tags completely" do
    html = ~s(<p>Hello</p><script>alert('xss')</script><p>World</p>)
    result = ContentSanitizer.sanitize(html)
    refute result =~ "script"
    refute result =~ "alert"
    assert result =~ "<p>Hello</p>"
    assert result =~ "<p>World</p>"
  end

  test "strips event handler attributes" do
    html = ~s(<p onmouseover="alert('xss')">Hover me</p>)
    result = ContentSanitizer.sanitize(html)
    refute result =~ "onmouseover"
    refute result =~ "alert"
    assert result =~ "<p>"
  end

  test "strips javascript: protocol in links" do
    html = ~s(<a href="javascript:alert('xss')">Click</a>)
    result = ContentSanitizer.sanitize(html)
    refute result =~ "javascript"
  end

  test "strips iframe tags" do
    html = ~s(<iframe src="https://evil.com"></iframe>)
    result = ContentSanitizer.sanitize(html)
    refute result =~ "iframe"
  end

  test "strips style tags" do
    html = ~s(<style>body{display:none}</style><p>Content</p>)
    result = ContentSanitizer.sanitize(html)
    refute result =~ "style"
    assert result =~ "<p>Content</p>"
  end

  test "allows images with safe src" do
    html = ~s(<img src="https://example.com/photo.jpg" alt="Photo">)
    result = ContentSanitizer.sanitize(html)
    assert result =~ "https://example.com/photo.jpg"
    assert result =~ ~s(alt="Photo")
  end

  test "handles nil input" do
    assert ContentSanitizer.sanitize(nil) == ""
  end
end